@inject OverlayService OverlayService

<Button OnClick="@OpenDialog">Open Dialog</Button>

@code {
    private async Task OpenDialog()
    {
        var result = await OverlayService.ShowDialogAsync<MyDialogContent>(
            title: "Edit Profile",
            parameters: new OverlayParameters().Add("UserId", 42));

        if (!result.Cancelled) { /* handle result */ }
    }
}

@inject OverlayService OverlayService

<Button OnClick="@OpenSheet">Open Sheet</Button>

@code {
    private async Task OpenSheet()
    {
        await OverlayService.ShowSheetAsync<MySheetContent>(
            title: "Settings",
            side: Lumeo.Side.Right);
    }
}

@inject OverlayService OverlayService

<Button Variant="Button.ButtonVariant.Destructive" OnClick="@Confirm">Delete</Button>

@code {
    private async Task Confirm()
    {
        var result = await OverlayService.ShowAlertDialogAsync(new AlertDialogOptions
        {
            Title = "Delete Item?",
            Description = "This action cannot be undone.",
            ConfirmText = "Delete",
            CancelText = "Cancel",
            IsDestructive = true
        });

        if (!result.Cancelled) { /* perform delete */ }
    }
}

