RadioGroupContext(
        string? Value,
        EventCallback<string> OnSelect,
        // Ordered, id-keyed registry (declaration order). Each entry is a DISTINCT
        // roving slot so duplicate Values stay independently keyboard-reachable.
        List<(string Id, string Value, bool Disabled)> Items,
        // Register/Replace/Unregister are keyed by the stable per-item id (see the
        // RadioGroup.razor registry helpers — mirrors Accordion's trigger registry).
        Action<string, string, bool> Register,
        Action<string, string, bool> Replace,
        Action<string> Unregister,
        // The role=radiogroup element id — the anchor for the DOM-order roving-nav
        // probe so arrow-key order tracks the live DOM after a keyed reorder.
        string ContainerId)

