@foreach (var size in Enum.GetValues<SheetContent.SheetSize>())
{
    <Sheet @bind-Open="@_sheetSizeOpen[size]">
        <SheetTrigger>
            <Button Variant="Button.ButtonVariant.Outline">@size</Button>
        </SheetTrigger>
        <SheetContent Size="@size">
            <SheetHeader>
                <SheetTitle>@size Sheet</SheetTitle>
                <SheetDescription>This sheet uses Size="SheetContent.SheetSize.@size"</SheetDescription>
            </SheetHeader>
            <Stack Gap="4" Class="py-4">
                <Lumeo.Text Size="sm" Color="muted">Sheet content goes here.</Lumeo.Text>
            </Stack>
        </SheetContent>
    </Sheet>
}

@code {
    private Dictionary<SheetContent.SheetSize, bool> _sheetSizeOpen =
        Enum.GetValues<SheetContent.SheetSize>().ToDictionary(s => s, _ => false);
}

